  ('heelevel3-6f0ba476-moex-00262', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '對有非薪資所得的代表性個人，就其所有所得課徵比例所得稅，或僅就薪資所得課徵比例薪資所 得稅，關於此兩種租稅對勞動供給曲線影響的差異，下列敘述何者正確？', '["只有前者會使其移動", "只有後者會使其移動", "兩者皆會使其移動", "兩者皆不會使其移動"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00263', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '當引進供給曲線為水平線的國際資金時，在可貸資金市場（loanablefundsmarket）且國內資金之 供給與需求分別符合供給法則與需求法則下，政府若採取只對國內儲蓄的利息收入課稅的政策， 國內均衡的投資會如何變化？', '["減少", "不變", "增加", "不一定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00264', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '甲在20年前以60萬元購入一資產，20年後以90萬元出售該資產。在資產持有期間，物價上漲率為 50%。在不計入賣出此資產利得前，甲的綜合所得淨額已達最高課稅級距的稅率40%。若政府對 物價變動予以指數化調整，則甲出售該資產的所得稅稅負，相較於沒有指數化調整，會產生多少 影響？', '["增加12萬元", "增加36萬元", "減少12萬元", "減少36萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00265', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '甲投資國內金融機構核准成立的證券投資信託基金，甲（受益人）對於該基金相關信託利益之所 得課稅方式，下列敘述何者正確？', '["該基金當年度收入減成本費用後有所得時，由甲併入所得發生年度之綜合所得稅申報", "由該基金為納稅義務人，依規定期限內辦理申報納稅", "該基金信託利益無須課稅", "該基金實際分配信託利益時，由受益人併入分配年度所得額課稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00266', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '下列各項所得，何者不一定符合我國之免稅所得規定？', '["公教人員所領的特支費", "甲出車禍，肇事方賠償他的賠償金", "乙於家族旅行途中意外死亡，公司給予其遺族撫卹金", "丙因受傷從保險公司所領取之保險給付"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00267', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '外國公司在臺灣設立之分公司，在中華民國境內經營國際運輸業務，成本費用分攤計算困難，得 向財政部申請核定以中華民國境內營業收入之一定比率計算所得額，下列比率何者正確？', '["10%", "15%", "25%", "30%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00268', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '根據新古典模型理論，下列何項租稅措施可有效提升廠商的投資意願？', '["調降個人所得稅稅率", "調降廠商的固定資本投資租稅抵減額", "調高公司所得稅稅率", "調降折舊費用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00269', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '所得稅法有關呆帳損失之規定，下列敘述何者錯誤？', '["營利事業提列備抵呆帳，以各種欠款債權餘額1%限度內提列為原則", "營利事業依法得列報實際發生呆帳之比率超過1%者，得以前3年度實際發生呆帳之比率平均數 提列備抵呆帳", "應收帳款因債務人倒閉逃匿致不能收回者，得視為實際發生呆帳損失", "債權列入呆帳損失後收回者，收回數額應列為收回年度之收益"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00270', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '我國A公司持有國外B公司60%的股份，其中B公司名下資產除現金200萬元外，僅有一棟於110年 1月購入位於新北市價值5,000萬元的房地產。假設A公司於110年10月將名下所有B公司之持股出 售，該股份交易所得應如何納稅？', '["無須繳納營利事業所得稅", "併入A公司當年度的基本所得額計算所得稅額", "依我國營利事業所得稅率20%繳稅", "按稅率45%計算稅額"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00271', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-112-3e700a6a', 'sub-heelevel3-6f0ba476-05', NULL, 'single_choice', '關於各種租稅課徵之主要理由，下列敘述何者錯誤？', '["菸酒稅是基於寓禁於徵的考量", "奢侈稅是基於公平的考量", "房地合一稅是經濟成長的考量", "碳關稅是基於資源配置效率的考量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:30+00:00", "source_pdf_sha1": "1185c3051054", "answer_pdf_sha1": "283879323c43", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "323", "s": "1001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "租稅各論", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
